   376→func (d *AlertsRouter) DroppedAlertmanagersFor(orgID int64) []*url.URL {
   377→	d.adminConfigMtx.RLock()
   378→	defer d.adminConfigMtx.RUnlock()
   379→	s, ok := d.externalAlertmanagers[orgID]
